(7, 'Grass');
INSERT INTO `cards_card` VALUES
(1, 'base1-1', 'Alakazam', 'Pokémon', '["Stage 2"]', 80, 'Rare Holo', '1', 'Ken Sugimori', 'Its brain can outperform a supercomputer. Its intelligence quotient is said to be 5000.', 'https://images.pokemontcg.io/base1/1.png', 'https://images.pokemontcg.io/base1/1_hires.png', 'Kadabra', '["Colorless", "Colorless", "Colorless"]', '2026-05-10 15:18:40.587501', '2026-05-10 15:21:42.320060', 1),
(2, 'base1-2', 'Blastoise', 'Pokémon', '["Stage 2"]', 100, 'Rare Holo', '2', 'Ken Sugimori', 'A brutal Pokémon with pressurized water jets on its shell. They are used for high-speed tackles.', 'https://images.pokemontcg.io/base1/2.png', 'https://images.pokemontcg.io/base1/2_hires.png', 'Wartortle', '["Colorless", "Colorless", "Colorless"]', '2026-05-10 15:18:40.598261', '2026-05-10 15:21:42.346072', 1),
(3, 'base1-3', 'Chansey', 'Pokémon', '["Basic"]', 120, 'Rare Holo', '3', 'Ken Sugimori', 'A rare and elusive Pokémon that is said to bring happiness to those who manage to catch it.', 'https://images.pokemontcg.io/base1/3.png', 'https://images.pokemontcg.io/base1/3_hires.png', '', '["Colorless"]', '2026-05-10 15:18:40.607066', '2026-05-10 15:21:42.365994', 1),
(4, 'base1-4', 'Charizard', 'Pokémon', '["Stage 2"]', 120, 'Rare Holo', '4', 'Mitsuhiro Arita', 'Spits fire that is hot enough to melt boulders. Known to unintentionally cause forest fires.', 'https://images.pokemontcg.io/base1/4.png', 'https://images.pokemontcg.io/base1/4_hires.png', 'Charmeleon', '["Colorless", "Colorless", "Colorless"]', '2026-05-10 15:18:40.616149', '2026-05-10 15:21:42.393265', 1),
(5, 'base1-5', 'Clefairy', 'Pokémon', '["Basic"]', 40, 'Rare Holo', '5', 'Ken Sugimori', 'Its magical and cute appeal has many admirers. It is rare and found only in certain areas.', 'https://images.pokemontcg.io/base1/5.png', 'https://images.pokemontcg.io/base1/5_hires.png', '', '["Colorless"]', '2026-05-10 15:18:40.625066', '2026-05-10 15:21:42.418116', 1),
(6, 'base1-6', 'Gyarados', 'Pokémon', '["Stage 1"]', 100, 'Rare Holo', '6', 'Mitsuhiro Arita', 'Rarely seen in the wild. Huge and vicious, it is capable of destroying entire cities in a rage.', 'https://images.pokemontcg.io/base1/6.png', 'https://images.pokemontcg.io/base1/6_hires.png', 'Magikarp', '["Colorless", "Colorless", "Colorless"]', '2026-05-10 15:18:40.632641', '2026-05-10 15:21:42.444741', 1),
(7, 'base1-7', 'Hitmonchan', 'Pokémon', '["Basic"]', 70, 'Rare Holo', '7', 'Ken Sugimori', 'While seeming to do nothing, it fires punches in lightning-fast volleys that are impossible to see.', 'https://images.pokemontcg.io/base1/7.png', 'https://images.pokemontcg.io/base1/7_hires.png', '', '["Colorless", "Colorless"]', '2026-05-10 15:18:40.638988', '2026-05-10 15:21:42.471186', 1),
(8, 'base1-8', 'Machamp', 'Pokémon', '["Stage 2"]', 100, 'Rare Holo', '8', 'Ken Sugimori', 'Using its amazing muscles, it throws powerful punches that can knock its victim clear over the horizon.', 'https://images.pokemontcg.io/base1/8.png', 'https://images.pokemontcg.io/base1/8_hires.png', 'Machoke', '["Colorless", "Colorless", "Colorless"]', '2026-05-10 15:18:40.648798', '2026-05-10 15:21:42.493610', 1),
(9, 'base1-9', 'Magneton', 'Pokémon', '["Stage 1"]', 60, 'Rare Holo', '9', 'Keiji Kinebuchi', 'Formed by several Magnemites linked together. It frequently appears when sunspots flare up.', 'https://images.pokemontcg.io/base1/9.png', 'https://images.pokemontcg.io/base1/9_hires.png', 'Magnemite', '["Colorless"]', '2026-05-10 15:18:40.655761', '2026-05-10 15:21:42.513509', 1),
(10, 'base1-10', 'Mewtwo', 'Pokémon', '["Basic"]', 60, 'Rare Holo', '10', 'Ken Sugimori', 'A scientist created this Pokémon after years of horrific gene-splicing and DNA engineering experiments.', 'https://images.pokemontcg.io/base1/10.png', 'https://images.pokemontcg.io/base1/10_hires.png', '', '["Colorless", "Colorless", "Colorless"]', '2026-05-10 15:18:40.665231', '2026-05-10 15:21:42.537020', 1),
(11, 'base1-11', 'Nidoking', 'Pokémon', '["Stage 2"]', 90, 'Rare Holo', '11', 'Ken Sugimori', 'Uses its powerful tail in battle to smash, constrict, then break its prey\'s bones.', 'https://images.pokemontcg.io/base1/11.png', 'https://images.pokemontcg.io/base1/11_hires.png', 'Nidorino', '["Colorless", "Colorless", "Colorless"]', '2026-05-10 15:18:40.671825', '2026-05-10 15:21:42.559372', 1),
(12, 'base1-12', 'Ninetales', 'Pokémon', '["Stage 1"]', 80, 'Rare Holo', '12', 'Ken Sugimori', 'Very smart and very vengeful. Grabbing one of its many tails could result in a 1,000-year curse.', 'https://images.pokemontcg.io/base1/12.png', 'https://images.pokemontcg.io/base1/12_hires.png', 'Vulpix', '["Colorless"]', '2026-05-10 15:18:40.681139', '2026-05-10 15:21:42.582337', 1),
(13, 'base1-13', 'Poliwrath', 'Pokémon', '["Stage 2"]', 90, 'Rare Holo', '13', 'Ken Sugimori', 'An adept swimmer at both the front crawl and breaststroke. Easily overtakes the best human swimmers.', 'https://images.pokemontcg.io/base1/13.png', 'https://images.pokemontcg.io/base1/13_hires.png', 'Poliwhirl', '["Colorless", "Colorless", "Colorless"]', '2026-05-10 15:18:40.688871', '2026-05-10 15:21:42.604809', 1),
(14, 'base1-14', 'Raichu', 'Pokémon', '["Stage 1"]', 80, 'Rare Holo', '14', 'Ken Sugimori', 'Its long tail serves as a ground to protect itself from its own high-voltage power.', 'https://images.pokemontcg.io/base1/14.png', 'https://images.pokemontcg.io/base1/14_hires.png', 'Pikachu', '["Colorless"]', '2026-05-10 15:18:40.695480', '2026-05-10 15:21:42.627462', 1),
(15, 'base1-15', 'Venusaur', 'Pokémon', '["Stage 2"]', 100, 'Rare Holo', '15', 'Mitsuhiro Arita', 'This plant blooms when it is absorbing solar energy. It stays on the move to seek sunlight.', 'https://images.pokemontcg.io/base1/15.png', 'https://images.pokemontcg.io/base1/15_hires.png', 'Ivysaur', '["Colorless", "Colorless"]', '2026-05-10 15:18:40.704788', '2026-05-10 15:21:42.649616', 1),
(16, 'base1-16', 'Zapdos', 'Pokémon', '["Basic"]', 90, 'Rare Holo', '16', 'Ken Sugimori', 'A legendary bird Pokémon said to appear from clouds while wielding enormous lightning bolts.', 'https://images.pokemontcg.io/base1/16.png', 'https://images.pokemontcg.io/base1/16_hires.png', '', '["Colorless", "Colorless", "Colorless"]', '2026-05-10 15:18:40.714385', '2026-05-10 15:21:42.669454', 1),
(17, 'base1-17', 'Beedrill', 'Pokémon', '["Stage 2"]', 80, 'Rare', '17', 'Ken Sugimori', 'Flies at high speed and attacks using the large, venomous stingers on its forelegs and tail.', 'https://images.pokemontcg.io/base1/17.png', 'https://images.pokemontcg.io/base1/17_hires.png', 'Kakuna', '[]', '2026-05-10 15:18:40.724232', '2026-05-10 15:21:42.691795', 1),
(18, 'base1-18', 'Dragonair', 'Pokémon', '["Stage 1"]', 80, 'Rare', '18', 'Mitsuhiro Arita', 'A mystical Pokémon that exudes a gentle aura. Has the ability to change climate conditions.', 'https://images.pokemontcg.io/base1/18.png', 'https://images.pokemontcg.io/base1/18_hires.png', 'Dratini', '["Colorless", "Colorless"]', '2026-05-10 15:18:40.733383', '2026-05-10 15:21:42.719400', 1),
(19, 'base1-19', 'Dugtrio', 'Pokémon', '["Stage 1"]', 70, 'Rare', '19', 'Keiji Kinebuchi', 'A team of Diglett triplets. It triggers huge earthquakes by burrowing 60 miles underground.', 'https://images.pokemontcg.io/base1/19.png', 'https://images.pokemontcg.io/base1/19_hires.png', 'Diglett', '["Colorless", "Colorless"]', '2026-05-10 15:18:40.740603', '2026-05-10 15:21:42.741903', 1),
(20, 'base1-20', 'Electabuzz', 'Pokémon', '["Basic"]', 70, 'Rare', '20', 'Ken Sugimori', 'Normally found near power plants, it can wander away and cause major blackouts in cities.', 'https://images.pokemontcg.io/base1/20.png', 'https://images.pokemontcg.io/base1/20_hires.png', '', '["Colorless", "Colorless"]', '2026-05-10 15:18:40.747983', '2026-05-10 15:21:42.768878', 1),
(21, 'base1-21', 'Electrode', 'Pokémon', '["Stage 1"]', 80, 'Rare', '21', 'Keiji Kinebuchi', 'It stores electrical energy under very high pressure. It often explodes with little or no provocation.', 'https://images.pokemontcg.io/base1/21.png', 'https://images.pokemontcg.io/base1/21_hires.png', 'Voltorb', '["Colorless"]', '2026-05-10 15:18:40.757044', '2026-05-10 15:21:42.791677', 1),
(22, 'base1-22', 'Pidgeotto', 'Pokémon', '["Stage 1"]', 60, 'Rare', '22', 'Ken Sugimori', 'Very protective of its sprawling territory, this Pokémon will fiercely peck at any intruder.', 'https://images.pokemontcg.io/base1/22.png', 'https://images.pokemontcg.io/base1/22_hires.png', 'Pidgey', '["Colorless"]', '2026-05-10 15:18:40.764718', '2026-05-10 15:21:42.811997', 1),
(23, 'base1-23', 'Arcanine', 'Pokémon', '["Stage 1"]', 100, 'Uncommon', '23', 'Ken Sugimori', 'A Pokémon that has been long admired for its beauty. It runs gracefully, as if on wings.', 'https://images.pokemontcg.io/base1/23.png', 'https://images.pokemontcg.io/base1/23_hires.png', 'Growlithe', '["Colorless", "Colorless", "Colorless"]', '2026-05-10 15:18:40.771210', '2026-05-10 15:21:42.840424', 1),
(24, 'base1-24', 'Charmeleon', 'Pokémon', '["Stage 1"]', 80, 'Uncommon', '24', 'Mitsuhiro Arita', 'When it swings its burning tail, it raises the temperature to unbearably high levels.', 'https://images.pokemontcg.io/base1/24.png', 'https://images.pokemontcg.io/base1/24_hires.png', 'Charmander', '["Colorless"]', '2026-05-10 15:18:40.778671', '2026-05-10 15:21:42.863185', 1),
(25, 'base1-25', 'Dewgong', 'Pokémon', '["Stage 1"]', 80, 'Uncommon', '25', 'Mitsuhiro Arita', 'Stores thermal energy in its body. Swims at a steady 8 knots even in intensely cold waters.', 'https://images.pokemontcg.io/base1/25.png', 'https://images.pokemontcg.io/base1/25_hires.png', 'Seel', '["Colorless", "Colorless", "Colorless"]', '2026-05-10 15:18:40.785503', '2026-05-10 15:21:42.886367', 1),
(26, 'base1-26', 'Dratini', 'Pokémon', '["Basic"]', 40, 'Uncommon', '26', 'Ken Sugimori', 'Long considered a mythical Pokémon until recently, when a small colony was found living underwater.', 'https://images.pokemontcg.io/base1/26.png', 'https://images.pokemontcg.io/base1/26_hires.png', '', '["Colorless"]', '2026-05-10 15:18:40.792151', '2026-05-10 15:21:42.909693', 1),
(27, 'base1-27', 'Farfetch\'d', 'Pokémon', '["Basic"]', 50, 'Uncommon', '27', 'Ken Sugimori', 'The sprig of green onions it holds is its weapon. This sprig is used much like a metal sword.', 'https://images.pokemontcg.io/base1/27.png', 'https://images.pokemontcg.io/base1/27_hires.png', '', '["Colorless"]', '2026-05-10 15:18:40.798755', '2026-05-10 15:21:42.927855', 1),
(28, 'base1-28', 'Growlithe', 'Pokémon', '["Basic"]', 60, 'Uncommon', '28', 'Ken Sugimori', 'Very protective of its territory. It will bark and bite to repel intruders from its space.', 'https://images.pokemontcg.io/base1/28.png', 'https://images.pokemontcg.io/base1/28_hires.png', '', '["Colorless"]', '2026-05-10 15:18:40.805463', '2026-05-10 15:21:42.954603', 1),
(29, 'base1-29', 'Haunter', 'Pokémon', '["Stage 1"]', 60, 'Uncommon', '29', 'Keiji Kinebuchi', 'Because of its ability to slip through block walls, it is said to be from another dimension.', 'https://images.pokemontcg.io/base1/29.png', 'https://images.pokemontcg.io/base1/29_hires.png', 'Gastly', '["Colorless"]', '2026-05-10 15:18:40.812064', '2026-05-10 15:21:42.974082', 1),
(30, 'base1-30', 'Ivysaur', 'Pokémon', '["Stage 1"]', 60, 'Uncommon', '30', 'Ken Sugimori', 'When the bulb on its back grows large, the Pokémon seems to lose the ability to stand on its hind legs.', 'https://images.pokemontcg.io/base1/30.png', 'https://images.pokemontcg.io/base1/30_hires.png', 'Bulbasaur', '["Colorless"]', '2026-05-10 15:18:40.818350', '2026-05-10 15:21:42.998059', 1),
(31, 'base1-31', 'Jynx', 'Pokémon', '["Basic"]', 70, 'Uncommon', '31', 'Ken Sugimori', 'Merely by meditating, the Pokémon launches a powerful psychic energy attack.', 'https://images.pokemontcg.io/base1/31.png', 'https://images.pokemontcg.io/base1/31_hires.png', '', '["Colorless", "Colorless"]', '2026-05-10 15:18:40.825272', '2026-05-10 15:21:43.021685', 1),
(32, 'base1-32', 'Kadabra', 'Pokémon', '["Stage 1"]', 60, 'Uncommon', '32', 'Ken Sugimori', 'It emits special alpha waves from its body that induce headaches even to those just nearby.', 'https://images.pokemontcg.io/base1/32.png', 'https://images.pokemontcg.io/base1/32_hires.png', 'Abra', '["Colorless", "Colorless", "Colorless"]', '2026-05-10 15:18:40.832222', '2026-05-10 15:21:43.044853', 1),
(33, 'base1-33', 'Kakuna', 'Pokémon', '["Stage 1"]', 80, 'Uncommon', '33', 'Keiji Kinebuchi', 'Almost incapable of moving, this Pokémon can only harden its shell to protect itself from predators.', 'https://images.pokemontcg.io/base1/33.png', 'https://images.pokemontcg.io/base1/33_hires.png', 'Weedle', '["Colorless", "Colorless"]', '2026-05-10 15:18:40.838611', '2026-05-10 15:21:43.068301', 1),
(34, 'base1-34', 'Machoke', 'Pokémon', '["Stage 1"]', 80, 'Uncommon', '34', 'Ken Sugimori', 'Its muscular body is so powerful that it must wear a power-save belt to help regulate its motions.', 'https://images.pokemontcg.io/base1/34.png', 'https://images.pokemontcg.io/base1/34_hires.png', 'Machop', '["Colorless", "Colorless", "Colorless"]', '2026-05-10 15:18:40.845449', '2026-05-10 15:21:43.090724', 1),
(35, 'base1-35', 'Magikarp', 'Pokémon', '["Basic"]', 30, 'Uncommon', '35', 'Mitsuhiro Arita', 'In the distant past, it was stronger than its horribly weak descendants that exist today.', 'https://images.pokemontcg.io/base1/35.png', 'https://images.pokemontcg.io/base1/35_hires.png', '', '["Colorless"]', '2026-05-10 15:18:40.852846', '2026-05-10 15:21:43.113509', 1),
(36, 'base1-36', 'Magmar', 'Pokémon', '["Basic"]', 50, 'Uncommon', '36', 'Ken Sugimori', 'Its body always burns with an orange glow that enables it to hide perfectly among flames.', 'https://images.pokemontcg.io/base1/36.png', 'https://images.pokemontcg.io/base1/36_hires.png', '', '["Colorless", "Colorless"]', '2026-05-10 15:18:40.859499', '2026-05-10 15:21:43.136197', 1),
(37, 'base1-37', 'Nidorino', 'Pokémon', '["Stage 1"]', 60, 'Uncommon', '37', 'Mitsuhiro Arita', 'An aggressive Pokémon that is quick to attack. The horn on its head secretes a powerful venom.', 'https://images.pokemontcg.io/base1/37.png', 'https://images.pokemontcg.io/base1/37_hires.png', 'Nidoran ♂', '["Colorless"]', '2026-05-10 15:18:40.865703', '2026-05-10 15:21:43.159136', 1),
(38, 'base1-38', 'Poliwhirl', 'Pokémon', '["Stage 1"]', 60, 'Uncommon', '38', 'Ken Sugimori', 'Capable of living in or out of water. When out of water, it sweats to keep its body slimy.', 'https://images.pokemontcg.io/base1/38.png', 'https://images.pokemontcg.io/base1/38_hires.png', 'Poliwag', '["Colorless"]', '2026-05-10 15:18:40.872326', '2026-05-10 15:21:43.181750', 1),
(39, 'base1-39', 'Porygon', 'Pokémon', '["Basic"]', 30, 'Uncommon', '39', 'Tomoaki Imakuni', 'A Pokémon that consists entirely of programming code. Capable of moving freely in cyberspace.', 'https://images.pokemontcg.io/base1/39.png', 'https://images.pokemontcg.io/base1/39_hires.png', '', '["Colorless"]', '2026-05-10 15:18:40.878760', '2026-05-10 15:21:43.204360', 1),
(40, 'base1-40', 'Raticate', 'Pokémon', '["Stage 1"]', 60, 'Uncommon', '40', 'Ken Sugimori', 'It uses its whiskers to maintain its balance. It seems to slow down if they are cut off.', 'https://images.pokemontcg.io/base1/40.png', 'https://images.pokemontcg.io/base1/40_hires.png', 'Rattata', '["Colorless"]', '2026-05-10 15:18:40.885031', '2026-05-10 15:21:43.232325', 1),
(41, 'base1-41', 'Seel', 'Pokémon', '["Basic"]', 60, 'Uncommon', '41', 'Ken Sugimori', 'The protruding horn on its head is very hard. This horn is used for bashing through thick ice.', 'https://images.pokemontcg.io/base1/41.png', 'https://images.pokemontcg.io/base1/41_hires.png', '', '["Colorless"]', '2026-05-10 15:18:40.891547', '2026-05-10 15:21:43.260460', 1),
(42, 'base1-42', 'Wartortle', 'Pokémon', '["Stage 1"]', 70, 'Uncommon', '42', 'Ken Sugimori', 'Often hides in water to stalk unweary prey. When swimming quickly, it moves its ears to maintain balance.', 'https://images.pokemontcg.io/base1/42.png', 'https://images.pokemontcg.io/base1/42_hires.png', 'Squirtle', '["Colorless"]', '2026-05-10 15:18:40.898152', '2026-05-10 15:21:43.280748', 1),
(43, 'base1-43', 'Abra', 'Pokémon', '["Basic"]', 30, 'Common', '43', 'Mitsuhiro Arita', 'Using its ability to read minds, it will identify impending danger and teleport to safety.', 'https://images.pokemontcg.io/base1/43.png', 'https://images.pokemontcg.io/base1/43_hires.png', '', '[]', '2026-05-10 15:18:40.904602', '2026-05-10 15:21:43.303984', 1),
(44, 'base1-44', 'Bulbasaur', 'Pokémon', '["Basic"]', 40, 'Common', '44', 'Mitsuhiro Arita', 'A strange seed was planted on its back at birth. Thus, a plant sprouted and now grows with this Pokémon.', 'https://images.pokemontcg.io/base1/44.png', 'https://images.pokemontcg.io/base1/44_hires.png', '', '["Colorless"]', '2026-05-10 15:18:40.911470', '2026-05-10 15:21:43.325025', 1),
(45, 'base1-45', 'Caterpie', 'Pokémon', '["Basic"]', 40, 'Common', '45', 'Ken Sugimori', 'Its short feet are tipped with suction pads that enable it to tirelessly climb slopes and walls.', 'https://images.pokemontcg.io/base1/45.png', 'https://images.pokemontcg.io/base1/45_hires.png', '', '["Colorless"]', '2026-05-10 15:18:40.918317', '2026-05-10 15:21:43.346091', 1),
(46, 'base1-46', 'Charmander', 'Pokémon', '["Basic"]', 50, 'Common', '46', 'Mitsuhiro Arita', 'Obviously prefers hot places. If it gets caught in the rain, steam is said to spout from the tip of its tail.', 'https://images.pokemontcg.io/base1/46.png', 'https://images.pokemontcg.io/base1/46_hires.png', '', '["Colorless"]', '2026-05-10 15:18:40.924696', '2026-05-10 15:21:43.367016', 1),
(47, 'base1-47', 'Diglett', 'Pokémon', '["Basic"]', 30, 'Common', '47', 'Keiji Kinebuchi', 'Lives about three feet underground, where it feeds on plant roots. It sometimes appears above ground.', 'https://images.pokemontcg.io/base1/47.png', 'https://images.pokemontcg.io/base1/47_hires.png', '', '[]', '2026-05-10 15:18:40.932311', '2026-05-10 15:21:43.390567', 1),
(48, 'base1-48', 'Doduo', 'Pokémon', '["Basic"]', 50, 'Common', '48', 'Mitsuhiro Arita', 'A bird that makes up for its poor flying with its fast foot speed. Leaves giant footprints.', 'https://images.pokemontcg.io/base1/48.png', 'https://images.pokemontcg.io/base1/48_hires.png', '', '[]', '2026-05-10 15:18:40.938627', '2026-05-10 15:21:43.418909', 1),
(49, 'base1-49', 'Drowzee', 'Pokémon', '["Basic"]', 50, 'Common', '49', 'Ken Sugimori', 'Puts enemies to sleep, then eats their dreams. Occasionally gets sick from eating bad dreams.', 'https://images.pokemontcg.io/base1/49.png', 'https://images.pokemontcg.io/base1/49_hires.png', '', '["Colorless"]', '2026-05-10 15:18:40.945529', '2026-05-10 15:21:43.445148', 1),
(50, 'base1-50', 'Gastly', 'Pokémon', '["Basic"]', 30, 'Common', '50', 'Keiji Kinebuchi', 'Almost invisible, this gaseous Pokémon cloaks the target and puts it to sleep without notice.', 'https://images.pokemontcg.io/base1/50.png', 'https://images.pokemontcg.io/base1/50_hires.png', '', '[]', '2026-05-10 15:18:40.951914', '2026-05-10 15:21:43.467370', 1),
(51, 'base1-51', 'Koffing', 'Pokémon', '["Basic"]', 50, 'Common', '51', 'Mitsuhiro Arita', 'Because it stores several kinds of toxic gases in its body, it is prone to exploding without warning.', 'https://images.pokemontcg.io/base1/51.png', 'https://images.pokemontcg.io/base1/51_hires.png', '', '["Colorless"]', '2026-05-10 15:18:40.958079', '2026-05-10 15:21:43.490370', 1),
(52, 'base1-52', 'Machop', 'Pokémon', '["Basic"]', 50, 'Common', '52', 'Mitsuhiro Arita', 'Loves to build its muscles. It trains in all styles of martial arts to become even stronger.', 'https://images.pokemontcg.io/base1/52.png', 'https://images.pokemontcg.io/base1/52_hires.png', '', '["Colorless"]', '2026-05-10 15:18:40.964575', '2026-05-10 15:21:43.511118', 1),
(53, 'base1-53', 'Magnemite', 'Pokémon', '["Basic"]', 40, 'Common', '53', 'Keiji Kinebuchi', 'Uses anti-gravity to stay suspended. Appears without warning and uses attacks like Thunder Wave.', 'https://images.pokemontcg.io/base1/53.png', 'https://images.pokemontcg.io/base1/53_hires.png', '', '["Colorless"]', '2026-05-10 15:18:40.971398', '2026-05-10 15:21:43.532493', 1),
(54, 'base1-54', 'Metapod', 'Pokémon', '["Stage 1"]', 70, 'Common', '54', 'Ken Sugimori', 'It is vulnerable to attack because its shell is soft, exposing its weak and tender body.', 'https://images.pokemontcg.io/base1/54.png', 'https://images.pokemontcg.io/base1/54_hires.png', 'Caterpie', '["Colorless", "Colorless"]', '2026-05-10 15:18:40.978159', '2026-05-10 15:21:43.556124', 1),
(55, 'base1-55', 'Nidoran ♂', 'Pokémon', '["Basic"]', 40, 'Common', '55', 'Ken Sugimori', 'Stiffens its ears to sense danger. The larger, more powerful of its horns secretes venom.', 'https://images.pokemontcg.io/base1/55.png', 'https://images.pokemontcg.io/base1/55_hires.png', '', '["Colorless"]', '2026-05-10 15:18:40.984880', '2026-05-10 15:21:43.579516', 1),
(56, 'base1-56', 'Onix', 'Pokémon', '["Basic"]', 90, 'Common', '56', 'Ken Sugimori', 'As it grows, the stone portions of its body harden to become similar to a diamond, though colored black.', 'https://images.pokemontcg.io/base1/56.png', 'https://images.pokemontcg.io/base1/56_hires.png', '', '["Colorless", "Colorless", "Colorless"]', '2026-05-10 15:18:40.991704', '2026-05-10 15:21:43.600527', 1),
(57, 'base1-57', 'Pidgey', 'Pokémon', '["Basic"]', 40, 'Common', '57', 'Ken Sugimori', 'A common sight in forests and woods. It flaps its wings at ground level to kick up blinding sand.', 'https://images.pokemontcg.io/base1/57.png', 'https://images.pokemontcg.io/base1/57_hires.png', '', '["Colorless"]', '2026-05-10 15:18:40.998249', '2026-05-10 15:21:43.623670', 1),
(58, 'base1-58', 'Pikachu', 'Pokémon', '["Basic"]', 40, 'Common', '58', 'Mitsuhiro Arita', 'When several of these Pokémon gather, their electricity can cause lightning storms.', 'https://images.pokemontcg.io/base1/58.png', 'https://images.pokemontcg.io/base1/58_hires.png', '', '["Colorless"]', '2026-05-10 15:18:41.004868', '2026-05-10 15:21:43.649002', 1),
(59, 'base1-59', 'Poliwag', 'Pokémon', '["Basic"]', 40, 'Common', '59', 'Ken Sugimori', 'Its newly grown legs prevent it from running. It appears to prefer swimming over trying to stand.', 'https://images.pokemontcg.io/base1/59.png', 'https://images.pokemontcg.io/base1/59_hires.png', '', '["Colorless"]', '2026-05-10 15:18:41.012072', '2026-05-10 15:21:43.672101', 1),
(60, 'base1-60', 'Ponyta', 'Pokémon', '["Basic"]', 40, 'Common', '60', 'Ken Sugimori', 'Its hooves are 10 times harder than diamonds. It can trample anything flat in moments.', 'https://images.pokemontcg.io/base1/60.png', 'https://images.pokemontcg.io/base1/60_hires.png', '', '["Colorless"]', '2026-05-10 15:18:41.018770', '2026-05-10 15:21:43.692912', 1),
(61, 'base1-61', 'Rattata', 'Pokémon', '["Basic"]', 30, 'Common', '61', 'Mitsuhiro Arita', 'Bites anything when it attacks. Small and very quick, it is a common sight in many places.', 'https://images.pokemontcg.io/base1/61.png', 'https://images.pokemontcg.io/base1/61_hires.png', '', '[]', '2026-05-10 15:18:41.025437', '2026-05-10 15:21:43.716573', 1),
(62, 'base1-62', 'Sandshrew', 'Pokémon', '["Basic"]', 40, 'Common', '62', 'Ken Sugimori', 'Burrows deep underground in arid locations far from water. It only emerges to hunt for food.', 'https://images.pokemontcg.io/base1/62.png', 'https://images.pokemontcg.io/base1/62_hires.png', '', '["Colorless"]', '2026-05-10 15:18:41.032267', '2026-05-10 15:21:43.742283', 1),
(63, 'base1-63', 'Squirtle', 'Pokémon', '["Basic"]', 40, 'Common', '63', 'Mitsuhiro Arita', 'After birth, its back swells and hardens into a shell. It powerfully sprays foam from its mouth.', 'https://images.pokemontcg.io/base1/63.png', 'https://images.pokemontcg.io/base1/63_hires.png', '', '["Colorless"]', '2026-05-10 15:18:41.038656', '2026-05-10 15:21:43.768723', 1),
(64, 'base1-64', 'Starmie', 'Pokémon', '["Stage 1"]', 60, 'Common', '64', 'Keiji Kinebuchi', 'Its central core glows with the seven colors of the rainbow. Some people value this core as a gem.', 'https://images.pokemontcg.io/base1/64.png', 'https://images.pokemontcg.io/base1/64_hires.png', 'Staryu', '["Colorless"]', '2026-05-10 15:18:41.045159', '2026-05-10 15:21:43.791989', 1),
(65, 'base1-65', 'Staryu', 'Pokémon', '["Basic"]', 40, 'Common', '65', 'Keiji Kinebuchi', 'An enigmatic Pokémon that can effortlessly regenerate any appendage it loses in battle.', 'https://images.pokemontcg.io/base1/65.png', 'https://images.pokemontcg.io/base1/65_hires.png', '', '["Colorless"]', '2026-05-10 15:18:41.051485', '2026-05-10 15:21:43.815262', 1),
(66, 'base1-66', 'Tangela', 'Pokémon', '["Basic"]', 50, 'Common', '66', 'Mitsuhiro Arita', 'Its whole body is swathed with wide vines that are similar to seaweed. These vines shake as it walks.', 'https://images.pokemontcg.io/base1/66.png', 'https://images.pokemontcg.io/base1/66_hires.png', '', '["Colorless", "Colorless"]', '2026-05-10 15:18:41.058117', '2026-05-10 15:21:43.836496', 1),
(67, 'base1-67', 'Voltorb', 'Pokémon', '["Basic"]', 40, 'Common', '67', 'Keiji Kinebuchi', 'Usually found in power plants. Easily mistaken for a Monster Ball, it has zapped many people.', 'https://images.pokemontcg.io/base1/67.png', 'https://images.pokemontcg.io/base1/67_hires.png', '', '["Colorless"]', '2026-05-10 15:18:41.064197', '2026-05-10 15:21:43.860200', 1),
(68, 'base1-68', 'Vulpix', 'Pokémon', '["Basic"]', 50, 'Common', '68', 'Ken Sugimori', 'At the time of birth, it has just one tail. Its tail splits from the tip as it grows older.', 'https://images.pokemontcg.io/base1/68.png', 'https://images.pokemontcg.io/base1/68_hires.png', '', '["Colorless"]', '2026-05-10 15:18:41.070870', '2026-05-10 15:21:43.880663', 1),
(69, 'base1-69', 'Weedle', 'Pokémon', '["Basic"]', 40, 'Common', '69', 'Mitsuhiro Arita', 'Often found in forests, eating leaves. It has a sharp, venomous stinger on its head.', 'https://images.pokemontcg.io/base1/69.png', 'https://images.pokemontcg.io/base1/69_hires.png', '', '["Colorless"]', '2026-05-10 15:18:41.077716', '2026-05-10 15:21:43.901407', 1),
(70, 'base1-70', 'Clefairy Doll', 'Trainer', '[]', 10, 'Rare', '70', 'Keiji Kinebuchi', '', 'https://images.pokemontcg.io/base1/70.png', 'https://images.pokemontcg.io/base1/70_hires.png', '', '[]', '2026-05-10 15:18:41.084758', '2026-05-10 15:21:43.922102', 1),
