INSERT INTO `cards_attack` VALUES
(115, 'Confuse Ray', 3, '["Psychic", "Psychic", "Psychic"]', 'Flip a coin. If heads, the Defending Pokémon is now Confused.', 0, 1, '30'),
(116, 'Hydro Pump', 3, '["Water", "Water", "Water"]', 'Does 40 damage plus 10 more damage for each Water Energy attached to Blastoise but not used to pay for this attack\'s Energy cost. Extra Water Energy after the 2nd doesn\'t count.', 0, 2, '40+'),
(117, 'Scrunch', 2, '["Colorless", "Colorless"]', 'Flip a coin. If heads, prevent all damage done to Chansey during your opponent\'s next turn. (Any other effects of attacks still happen.)', 0, 3, ''),
(118, 'Double-edge', 4, '["Colorless", "Colorless", "Colorless", "Colorless"]', 'Chansey does 80 damage to itself.', 1, 3, '80'),
(119, 'Fire Spin', 4, '["Fire", "Fire", "Fire", "Fire"]', 'Discard 2 Energy cards attached to Charizard in order to use this attack.', 0, 4, '100'),
(120, 'Sing', 1, '["Colorless"]', 'Flip a coin. If heads, the Defending Pokémon is now Asleep.', 0, 5, ''),
(121, 'Metronome', 3, '["Colorless", "Colorless", "Colorless"]', 'Choose 1 of the Defending Pokémon\'s attacks. Metronome copies that attack except for its Energy costs and anything else required in order to use that attack, such as discarding Energy cards. (No matter what type the Defending Pokémon is, Clefairy\'s type is still Colorless.)', 1, 5, ''),
(122, 'Dragon Rage', 3, '["Water", "Water", "Water"]', '', 0, 6, '50'),
(123, 'Bubblebeam', 4, '["Water", "Water", "Water", "Water"]', 'Flip a coin. If heads, the Defending Pokémon is now Paralyzed.', 1, 6, '40'),
(124, 'Jab', 1, '["Fighting"]', '', 0, 7, '20'),
(125, 'Special Punch', 3, '["Fighting", "Fighting", "Colorless"]', '', 1, 7, '40'),
